data.config_example:
import readtime from "@plugdash/readtime"
// in emdash plugins array:
readtime({ collections: ["blog"] })

import callout from "@plugdash/callout"
// in emdash plugins array:
callout()

import sharepost from "@plugdash/sharepost"
// in emdash plugins array:
sharepost({ via: "abhinavs" })

import heartpost from "@plugdash/heartpost"
// in emdash plugins array:
heartpost()

import shortlink from "@plugdash/shortlink"
// in emdash plugins array:
shortlink({ autoCreate: true })

import tocgen from "@plugdash/tocgen"
// in emdash plugins array:
tocgen({ minHeadings: 3 })

// engage is not registered in astro.config.mjs.
// Register heartpost, sharepost, and shortlink instead,
// then import EngagementBar.astro directly:

import autobuild from "@plugdash/autobuild"
// in emdash plugins array:
autobuild({
  hookUrl: import.meta.env.CF_PAGES_DEPLOY_HOOK,
  allowedHosts: ["api.cloudflare.com"],
})
